boot.shared:
// 三载体一致:纯 JS CPU 内核,无 DOM。data.program 是已编译的 Uint16Array 机器码;全部命名导出
import { CPU, avrInstruction, AVRIOPort, AVRTimer, portBConfig, timer0Config, PinState } from 'https://cdn.jsdelivr.net/npm/avr8js@0.21.0/+esm';
const cpu = new CPU(data.program);
const portB = new AVRIOPort(cpu, portBConfig);
new AVRTimer(cpu, timer0Config); // 定时器/PWM/millis 需要它
portB.addListener(() => { const s = portB.pinState(5); /* s===PinState.High → 点亮 LED,自绘 */ });
// run loop(每帧推进若干周期):
for (let i = 0; i < 50000; i++) { avrInstruction(cpu); cpu.tick(); }
